CREATE OR REPLACE FUNCTION is_admin() RETURNS boolean AS $\$ BEGIN RETURN (auth.jwt() -> 'app_metadata' ->> 'is_superadmin')::boolean = true OR EXISTS(SELECT 1 FROM public.constructoras WHERE id = auth.uid() AND role IN ('admin', 'superadmin')); END; $\$ LANGUAGE plpgsql SECURITY DEFINER; CREATE OR REPLACE FUNCTION is_superadmin() RETURNS boolean AS $\$ BEGIN RETURN (auth.jwt() -> 'app_metadata' ->> 'is_superadmin')::boolean = true OR EXISTS(SELECT 1 FROM public.constructoras WHERE id = auth.uid() AND role = 'superadmin'); END; $\$ LANGUAGE plpgsql SECURITY DEFINER;
